//src.components/MyPet/MyPetForm.jsx

//나의 반려견 등록 페이지 백엔드 엔드포인트 : /api/pet/enroll



import React, { useState } from "react";
import axios from "axios";
import './MyPetForm.css';


function MyPetForm() {

    const [form, setForm] = useState({
        name: '',
        profile: 'null',
        adopt: '',
        type: '',
        weight: '',
        size: '',
        age: '',
        gender: '',
        petId: '',
    });
    const [errors, setErrors] = useState({});
    const [isLoading, setIsLoading] = useState(false);

    const handleChange = (e) => {
        const { name, value, type, files } = e.target;

        setForm({
            ...form,
            [name]: type === "file" ? files[0] : value,
        });

        if (errors[name]) {
            setErrors({ ...errors, [name]: '' });
        }
    };

    const validateForm = () => {
        const newErrors = {};

        if (!form.name.trim()) {
            newErrors.name = '반려견의 이름을 입력해주세요';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    }

    const handleSubmit = async (e) => {
        e.preventDefault();
        console.log("🟡 handleSubmit called"); // ← 이거 확인
        if (!validateForm()) {
            console.log("🔴 유효성 검사 실패", errors); // ← 여기서 막히는지
            return;
        }

        setIsLoading(true);
        console.log("🟢 유효성 통과, 서버에 전송 시작");

        try {
            //백엔드 반려견 등록 POST
            const formData = new FormData();
            for (let key in form) {
                formData.append(key, form[key]);
            }

            await axios.post('/api/pet/enroll', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data'
                }
            });
            alert('반려견 등록이 완료되었습니다! 🐕');

            setForm({
                name: '',
                profile: 'null',
                adopt: '',
                type: '',
                weight: '',
                size: '',
                age: '',
                gender: '',
                petID: '',
            });
        } catch (error) {
            console.error(error);
            alert("반려견 등록 실패: " + (error.response?.data || "오류가 발생했습니다."));
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="mypet-container">
            <div className="mypet-card">
                <div className="form-header">
                    <div className="paw-icon">🐾</div>
                    <h2>나의 반려동물 프로필</h2>
                    <p>소중한 반려견의 정보를 등록해주세요</p>
                </div>

                <form onSubmit={handleSubmit} className="mypet-form">
                    <div className="form-group">
                        <label htmlFor="name">이름 *</label>
                        <input
                            id="name"
                            name="name"
                            type="text"
                            placeholder="꼬미"
                            value={form.name}
                            onChange={handleChange}
                            className={errors.name ? 'error' : ''}
                        />
                        {errors.name && <span className="error-message">{errors.name}</span>}
                    </div>

                    {/* 프로필 사진 */}
                    <div className="form-group">
                        <label htmlFor="profile">프로필 사진 *</label>
                        <input
                            id="profile"
                            name="profile"
                            type="file"
                            accept="image/*"
                            onChange={handleChange}
                        />
                    </div>

                    {/* 입양 여부 */}
                    <div className="form-group">
                        <label>입양 여부 *</label>
                        <div className="radio-group">
                            <label>
                                <input type="radio" name="adopt" value="yes" checked={form.adopt === 'yes'} onChange={handleChange} />
                                <span>예</span>
                            </label>
                            <label>
                                <input type="radio" name="adopt" value="no" checked={form.adopt === 'no'} onChange={handleChange} />
                                <span>아니오</span>
                            </label>
                        </div>
                    </div>

                    {/* 품종 */}
                    <div className="form-group">
                        <label htmlFor="type">반려견 품종 *</label>
                        <input
                            id="type"
                            name="type"
                            type="text"
                            placeholder="푸들"
                            value={form.type}
                            onChange={handleChange}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="weight">반려견 몸무게 *</label>
                        <div className="input-with-unit">
                            <input
                                id="weight"
                                name="weight"
                                type="text"
                                placeholder="5"
                                value={form.weight}
                                onChange={handleChange}
                            />
                            <span>kg</span>
                        </div>
                    </div>

                    {/* 사이즈 */}
                    <div className="form-group">
                        <label htmlFor="size">반려견 사이즈 *</label>
                        <select
                            id="size"
                            name="size"
                            value={form.size}
                            onChange={handleChange}
                        >
                            <option value="">선택</option>
                            <option value="LARGE">대형견</option>
                            <option value="MEDIUM">중현견</option>
                            <option value="SMALL">소형견</option>
                        </select>
                    </div>

                    {/* 나이 */}
                    <div className="form-group">
                        <label htmlFor="age">반려견 나이 *</label>
                        <div className="input-with-unit">
                            <input
                                id="age"
                                name="age"
                                type="text"
                                placeholder="5"
                                value={form.age}
                                onChange={handleChange}
                            />
                            <span>살</span>
                        </div>
                    </div>

                    {/* 성별 */}
                    <div className="form-group">
                        <label>반려견 성별 *</label>
                        <div className="radio-group">
                            <label>
                                <input type="radio" name="gender" value="FEMALE" checked={form.gender === 'FEMALE'} onChange={handleChange} />
                                <span>암컷</span>
                            </label>
                            <label>
                                <input type="radio" name="gender" value="MALE" checked={form.gender === 'MALE'} onChange={handleChange} />
                                <span>수컷</span>
                            </label>
                            <label>
                                <input type="radio" name="gender" value="NEUTER" checked={form.gender === 'NEUTER'} onChange={handleChange} />
                                <span>중성</span>
                            </label>
                        </div>
                    </div>


                    <div className="form-group">
                        <label htmlFor="petId">반려견 등록번호 *</label>
                        <input
                            id="petId"
                            name="petId"
                            type="text"
                            value={form.petId}
                            onChange={handleChange}
                        />
                    </div>

                    <button
                        type="submit"
                        className={`submit-btn ${isLoading ? 'loading' : ''}`}
                        disabled={isLoading}
                    >
                        {isLoading ? (
                            <>
                                <span className="loading-spinner"></span>
                                등록 중...
                            </>
                        ) : (
                            '등록 완료 🐕'
                        )}
                    </button>
                </form>
            </div>
        </div>
    );
}

export default MyPetForm;
